import type { SupplierQuotation } from '../types';import { SupplierStatusBadge } from './SupplierStatusBadge';
export const QuotationTable=({quotations,isLoading,onEdit,showSupplier=true}:{quotations:SupplierQuotation[];isLoading:boolean;onEdit?:(q:SupplierQuotation)=>void;showSupplier?:boolean})=>{if(isLoading)return <div className="space-y-3 p-5">{Array.from({length:5}).map((_,i)=><div key={i} className="h-12 animate-pulse rounded bg-slate-100 dark:bg-slate-800"/>)}</div>;if(!quotations.length)return <p className="p-10 text-center text-sm text-slate-500">No quotations found.</p>;return <div className="overflow-x-auto"><table className="min-w-full text-left text-sm"><thead className="border-b bg-slate-50 text-xs uppercase text-slate-500 dark:border-slate-700 dark:bg-slate-800"><tr><th className="px-4 py-3">Quotation</th>{showSupplier?<th className="px-4 py-3">Supplier</th>:null}<th className="px-4 py-3">RFQ</th><th className="px-4 py-3">Date / Validity</th><th className="px-4 py-3">Amount</th><th className="px-4 py-3">Status</th><th className="px-4 py-3">Actions</th></tr></thead><tbody className="divide-y dark:divide-slate-800">{quotations.map(q=><tr key={q.id}><td className="px-4 py-3"><p className="font-mono font-semibold">{q.quotation_number}</p><p className="text-xs text-slate-400">{q.item_count??q.items?.length??0} items</p></td>{showSupplier?<td className="px-4 py-3 font-semibold">{q.supplier_name}</td>:null}<td className="px-4 py-3 font-mono text-xs">{q.rfq_reference||'—'}</td><td className="px-4 py-3"><p>{q.quotation_date}</p><p className="text-xs text-slate-400">Valid: {q.valid_until||'Not set'}</p></td><td className="px-4 py-3 font-semibold tabular-nums">{q.currency} {Number(q.total_amount).toLocaleString()}</td><td className="px-4 py-3"><SupplierStatusBadge status={q.status}/></td><td className="px-4 py-3">{onEdit?<button className="text-xs font-semibold text-indigo-600" onClick={()=>onEdit(q)}>Edit</button>:null}</td></tr>)}</tbody></table></div>;};
